import React, { useState } from "react";

const SearchBar = ({ onSearch, onCategoryChange }) => {

  // 🔹 Categories
  const categories = ["All", "Personal", "Work", "Study", "Health", "Finance", "All", "Personal", "Work", "Study", "Health", "Finance"];

  // 🔹 State
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");

  // 🔹 Search handler
  const handleSearch = (e) => {
    const value = e.target.value;
    setSearch(value);
    onSearch && onSearch(value);
  };

  // 🔹 Category handler
  const handleCategory = (cat) => {
    setSelectedCategory(cat);
    onCategoryChange && onCategoryChange(cat);
  };

  return (
    <div className="w-full space-y-4">

      {/* 🔍 Search Input */}
      <div className="w-full">
        <input
          type="text"
          placeholder="🔍 Search tasks..."
          value={search}
          onChange={handleSearch}
          className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white placeholder-white/60 focus:outline-none focus:ring-2 focus:ring-white/30"
        />
      </div>

      {/* 📂 Categories */}
      <div className="flex flex-wrap gap-2 sm:gap-3">

        {categories.map((cat, i) => (
          <button
            key={i}
            onClick={() => handleCategory(cat)}
            className={`px-3 sm:px-4 py-1.5 sm:py-2 rounded-full text-xs sm:text-sm transition ${
              selectedCategory === cat
                ? "bg-white text-black"
                : "bg-white/10 text-white hover:bg-white/20"
            }`}
          >
            {cat}
          </button>
        ))}

      </div>

    </div>
  );
};

export default SearchBar;
